t.script:
                let videoStream = null;
                let scanInterval = null;

                async function startScanner() {
                    try {
                        const video = document.getElementById('qr-video');
                        const placeholder = document.getElementById('qr-placeholder');

                        videoStream = await navigator.mediaDevices.getUserMedia({
                            video: { facingMode: 'environment' }
                        });

                        video.srcObject = videoStream;
                        video.classList.remove('hidden');
                        placeholder.classList.add('hidden');

                        document.getElementById('btn-start').classList.add('hidden');
                        document.getElementById('btn-stop').classList.remove('hidden');

                        // Simple frame scanning using canvas
                        const canvas = document.getElementById('qr-canvas');
                        const ctx = canvas.getContext('2d');

                        scanInterval = setInterval(() => {
                            if (video.readyState === video.HAVE_ENOUGH_DATA) {
                                canvas.width = video.videoWidth;
                                canvas.height = video.videoHeight;
                                ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
                                // Note: Full QR decoding requires a JS library.
                                // For now, admin can use the manual input for the token.
                            }
                        }, 500);

                    } catch (err) {
                        alert('Camera access denied or not available. Please use manual token input.');
                    }
                }

                function stopScanner() {
                    if (videoStream) {
                        videoStream.getTracks().forEach(t => t.stop());
                        videoStream = null;
                    }
                    if (scanInterval) {
                        clearInterval(scanInterval);
                        scanInterval = null;
                    }

                    const video = document.getElementById('qr-video');
                    const placeholder = document.getElementById('qr-placeholder');
                    video.classList.add('hidden');
                    placeholder.classList.remove('hidden');

                    document.getElementById('btn-start').classList.remove('hidden');
                    document.getElementById('btn-stop').classList.add('hidden');
                }

                async function verifyToken(token) {
                    if (!token || !token.trim()) {
                        alert('Please enter a valid QR token.');
                        return;
                    }

                    try {
                        const res = await fetch('/api/qr/verify', {
                            method: 'POST',
                            headers: { 'Content-Type': 'application/json' },
                            body: JSON.stringify({ token: token.trim() })
                        });

                        const data = await res.json();

                        if (data.error) {
                            document.getElementById('scan-result').classList.remove('hidden');
                            document.getElementById('scan-empty').classList.add('hidden');
                            document.getElementById('result-content').innerHTML = `


                                    error ${data.error}
                                `;
                            return;
                        }

                        const tx = data.transaction;
                        const isPickupReady = tx.current_status === 'ready_for_pickup';

                        document.getElementById('scan-result').classList.remove('hidden');
                        document.getElementById('scan-empty').classList.add('hidden');
                        document.getElementById('result-content').innerHTML = `








${tx.book_title}

${tx.book_author}

Transaction: ${tx.name}






                                        Member
                                        ${tx.user_name}



                                        Email
                                        ${tx.user_email}



                                        Type
                                        ${tx.type}



                                        Amount
                                        Rp ${new Intl.NumberFormat('id-ID').format(tx.total_amount)}



                                        Status
                                        ${tx.current_status.replace(/_/g, ' ')}



                                        Duration
                                        ${tx.borrow_duration} days


                                ${isPickupReady ? `

                                    check_circle Confirm Book Pickup

                                ` : `


                                    This transaction is already in "${tx.current_status.replace(/_/g, ' ')}" status.

                                `}
                            `;

                    } catch (err) {
                        alert('Network error. Please try again.');
                    }
                }

                async function confirmPickup(token) {
                    try {
                        const res = await fetch('/api/qr/confirm-pickup', {
                            method: 'POST',
                            headers: { 'Content-Type': 'application/json' },
                            body: JSON.stringify({ token: token })
                        });

                        const data = await res.json();

                        if (data.error) {
                            alert('Error: ' + data.error);
                            return;
                        }

                        document.getElementById('result-content').innerHTML = `




                                    check_circle


Pickup Confirmed!

${data.message}

Due date: ${data.due_date}

                                    Scan Another

                            `;

                    } catch (err) {
                        alert('Network error. Please try again.');
                    }
                }
